create table order_item_status_history (
    id            number generated by default as identity not null enable,
    order_item_id varchar2(30 byte),
    old_status    varchar2(30 byte),
    new_status    varchar2(30 byte),
    changed_at    timestamp(6) default systimestamp,
    changed_by    varchar2(200 byte),
    change_notes  varchar2(1000 byte)
);

create unique index pk_order_item_status_history on
    order_item_status_history (
        id
    );

alter table order_item_status_history
    add constraint pk_order_item_status_history primary key ( id )
        using index pk_order_item_status_history enable;

